import React, { useEffect, useState, useRef } from 'react';

const TransparentLogo = ({ src, alt, className, style, onClick }) => {
  const [dataUrl, setDataUrl] = useState(src);
  const canvasRef = useRef(null);

  useEffect(() => {
    const img = new Image();
    img.crossOrigin = "Anonymous";
    img.onload = () => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d');
      canvas.width = img.width;
      canvas.height = img.height;
      ctx.drawImage(img, 0, 0);

      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      const data = imageData.data;

      for (let i = 0; i < data.length; i += 4) {
        const r = data[i];
        const g = data[i + 1];
        const b = data[i + 2];

        // Calculate brightness
        const brightness = (r + g + b) / 3;

        // The background is a bright green gradient. The logo itself is dark green.
        // If brightness > 120 and green is the dominant color, it's the background.
        if (brightness > 130 && g > r && g > b * 0.8) {
          // Smooth anti-aliasing edge based on brightness
          let alpha = 255 - (brightness - 130) * 3;
          if (alpha < 0) alpha = 0;
          if (alpha > 255) alpha = 255;
          data[i + 3] = alpha;
        } else if (brightness > 220) {
           // Extremely bright pixels (top left corner of gradient)
           data[i + 3] = 0;
        }
      }

      ctx.putImageData(imageData, 0, 0);
      setDataUrl(canvas.toDataURL("image/png"));
    };
    img.src = src;
  }, [src]);

  return (
    <>
      <canvas ref={canvasRef} style={{ display: 'none' }} />
      <img src={dataUrl} alt={alt} className={className} style={style} onClick={onClick} />
    </>
  );
};

export default TransparentLogo;
